use actix_files as fs;
use actix_web::{web, App, HttpResponse, HttpServer};
use actix_web_actors::ws;
use std::path::PathBuf;

async fn handle_file(info: web::Data<fs::NamedFile>) -> HttpResponse {
    match info.into_result() {
        Ok(file) => HttpResponse::Ok().body(file),
        Err(err) => {
            println!("Failed to read file, reason: {}", err);
            HttpResponse::BadRequest().finish()
        }
    }
}

#[actix_web::main]
async fn main() -> std::io::Result<()> {
    let path = PathBuf::from("./uploads");

    println!(
        "Serving files from {} at http://localhost:8080/files",
        path.display(),
    );

    HttpServer::new(move || {
        App::new().service(
            web::scope("/files")
                .route(&[&ws], web::get().to_async(handle_file)),
        )
    })
    // Listen on port 8080 and spawns n threads
    .bind("127.0.0.1:8080")?
    .run_until_stopped()
}